    companion object {
        private const val AUTHENTICATED_KEY = "is_authenticated"
        private const val SHARED_PREFS_NAME = "app_prefs"
        private const val TAG = "BiometricAuth"
        private const val KEY_NAME = "biometric_auth_key"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        sharedPreferences = getSharedPreferences(SHARED_PREFS_NAME, Context.MODE_PRIVATE)

        if (isAuthenticated()) {
            navigateToHomeScreen()
            return
        }

        setContentView(R.layout.activity_main) // Assuming you have an activity_main.xml with a login button

        val loginButton: Button = findViewById(R.id.loginButton)
        loginButton.setOnClickListener {
            handleLoginAttempt()
        }

        executor = ContextCompat.getMainExecutor(this)
        setupBiometricPrompt()
        setupKeystore()

        // Optionally, trigger biometric prompt automatically on app launch if not authenticated
        // and if biometric is available
        if (isBiometricAvailable()) {
            showBiometricPrompt()
        }
    }

    private fun isAuthenticated(): Boolean {
        return sharedPreferences.getBoolean(AUTHENTICATED_KEY, false)
    }

    private fun setAuthenticated(isAuthenticated: Boolean) {
        sharedPreferences.edit().putBoolean(AUTHENTICATED_KEY, isAuthenticated).apply()
    }

    private fun navigateToHomeScreen() {
        val intent = Intent(this, HomeScreenActivity::class.java)
        startActivity(intent)
        finish()
    }

    private fun handleLoginAttempt() {
        if (isBiometricAvailable()) {
            showBiometricPrompt()
        } else {
            // Fallback to password/PIN login if biometric is not available or disabled
            showPasswordLogin()
        }
    }

    private fun isBiometricAvailable(): Boolean {
        val biometricManager = BiometricManager.from(this)
        return when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                Log.d(TAG, "App can authenticate using biometrics.")
                true
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                Log.e(TAG, "No biometric features available on this device.")
                false
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                Log.e(TAG, "Biometric features are currently unavailable.")
                false
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                Log.e(TAG, "The user hasn't associated any biometric credentials with their account.")
                // Prompt user to enroll biometrics
                false
            }
            BiometricManager.BIOMETRIC_ERROR_SECURITY_FICTION -> {
                Log.e(TAG, "The user has not set up any biometrics, or they are currently locked out.")
                false
            }
            else -> {
                Log.e(TAG, "Unknown biometric error.")
                false
            }
        }
    }

    private fun setupKeystore() {
        try {
            keystore = KeyStore.getInstance("AndroidKeyStore")
            keystore.load(null) // Load the KeyStore
            val keyGenerator = android.security.keystore.KeyGenerator.getInstance(
                KeyProperties.KEY_ALGORITHM_AES,
                "AndroidKeyStore"
            )
            keyGenerator.init(
                KeyGenParameterSpec.Builder(
                    KEY_NAME,
                    KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
                )
                    .setBlockModes(KeyProperties.BLOCK_MODE_CBC)
                    .setUserAuthenticationRequired(true)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_PKCS7)
                    .build()
            )
            keyGenerator.generateKey()
        } catch (e: Exception) {
            when (e) {
                is KeyStoreException, is CertificateException, is IOException,
                is NoSuchAlgorithmException, is NoSuchProviderException,
                is InvalidAlgorithmParameterException -> {
                    Log.e(TAG, "Keystore setup failed: ${e.message}", e)
                }
                else -> throw e
            }
        }
    }

    private fun setupBiometricPrompt() {
        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Log.e(TAG, "Biometric authentication error: $errorCode - $errString")
                    Toast.makeText(applicationContext, "Authentication error: $errString", Toast.LENGTH_SHORT).show()
                    // Fallback to password/PIN login
                    showPasswordLogin()
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    Log.d(TAG, "Biometric authentication succeeded!")
                    Toast.makeText(applicationContext, "Authentication succeeded!", Toast.LENGTH_SHORT).show()
                    setAuthenticated(true)
                    navigateToHomeScreen()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Log.w(TAG, "Biometric authentication failed.")
                    Toast.makeText(applicationContext, "Authentication failed. Try again.", Toast.LENGTH_SHORT).show()
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Login with Biometrics")
            .setSubtitle("Authenticate using your fingerprint or face to proceed")
            .setNegativeButtonText("Use password instead")
            .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.DEVICE_CREDENTIAL) // DEVICE_CREDENTIAL for PIN/Pattern/Password fallback
            .build()
    }

    private fun showBiometricPrompt() {
        try {
            // Get the SecretKey for biometric authentication
            val secretKey = keystore.getKey(KEY_NAME, null)
            val cipher = android.security.keystore.KeyGenerator.getInstance(
                KeyProperties.KEY_ALGORITHM_AES,
                "AndroidKeyStore"
            ).generateKey().let {
                android.security.keystore.KeyGenerator.getInstance(
                    KeyProperties.KEY_ALGORITHM_AES,
                    "AndroidKeyStore"
                ).run {
                    init(
                        KeyGenParameterSpec.Builder(
                            KEY_NAME,
                            KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
                        )
                            .setBlockModes(KeyProperties.BLOCK_MODE_CBC)
                            .setUserAuthenticationRequired(true)
                            .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_PKCS7)
                            .build()
                    )
                    generateKey()
                }
            }.let {
                javax.crypto.Cipher.getInstance(
                    "${KeyProperties.KEY_ALGORITHM_AES}/${KeyProperties.BLOCK_MODE_CBC}/${KeyProperties.ENCRYPTION_PADDING_PKCS7}"
                ).apply { init(javax.crypto.Cipher.ENCRYPT_MODE, it) }
            }

            biometricPrompt.authenticate(promptInfo, BiometricPrompt.CryptoObject(cipher))
        } catch (e: Exception) {
            Log.e(TAG, "Error showing biometric prompt with crypto object: ${e.message}", e)
            Toast.makeText(this, "Biometric error: Please try again or use password.", Toast.LENGTH_SHORT).show()
            showPasswordLogin() // Fallback if crypto object setup fails
        }
    }

    private fun showPasswordLogin() {
        Toast.makeText(this, "Proceeding to password login...", Toast.LENGTH_SHORT).show()
