// Dummy HomeScreenActivity to navigate to
class HomeScreenActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_home_screen) // Assume you have an activity_home_screen.xml
        Toast.makeText(this, "Welcome to the Home Screen!", Toast.LENGTH_LONG).show()

        val logoutButton: Button = findViewById(R.id.logoutButton)
        logoutButton.setOnClickListener {
            val sharedPreferences = getSharedPreferences(MainActivity.SHARED_PREFS_NAME, Context.MODE_PRIVATE)
            sharedPreferences.edit().putBoolean(MainActivity.AUTHENTICATED_KEY, false).apply()
            val intent = Intent(this, MainActivity::class.java)
            startActivity(intent)
            finish()
        }
    }
}

